@spec timing_period_spec  src=tests/specs/timing_period_spec.lua  loc=83  sha=fa4a61d  cases=8
@exercises timing (timing)
@surface   timing.compositePeriodQN

# Intent
  Pin compositePeriodQN: smallest T at which all factor tiles complete.
  Tile period = period × pulsesPerCycle, so lilt (pulsesPerCycle=2)
  contributes double its declared period to the LCM. For rationals
  nᵢ/dᵢ the result is lcm(nᵢ)/gcd(dᵢ).

# Cases
  @case 'empty composite falls back to 1 qn'  [pure]  @ 12-16
  @case 'single classic factor: tile period = declared period'  [pure]  @ 19-24
  @case 'single lilt factor: tile period doubles via pulsesPerCycle'  [pure]  @ 27-32
  @case 'lcm with lilt doubling: classic@2, lilt@3 → lcm(2,6) = 6'  [pure]  @ 35-41
  @case 'lcm with lilt doubling: classic@2, lilt@4 → lcm(2,8) = 8'  [pure]  @ 44-50
  @case 'fractional periods with lilt doubling: lcm(1,2)/gcd(2,3) = 2'  [pure]  @ 53-60
  @case 'mixed: classic@1 + lilt@1/2 → lcm(1,2)/gcd(1,2) = 2'  [pure]  @ 63-70
  @case 'pocket doubles: classic@1 + pocket@1 → lcm(1,2) = 2'  [pure]  @ 73-81

# Uses (outbound edges)
  @use call timing.compositePeriodQN  @ 14,15
